The pipe takes the output of one function and passes it as the first argument to the next:

# Without pipe
summarize(group_by(filter(mtcars, cyl == 4), gear), avg_mpg = mean(mpg))

# With pipe -- reads left to right, top to bottom
mtcars |&gt;
  filter(cyl == 4) |&gt;
  group_by(gear) |&gt;
  summarize(avg_mpg = mean(mpg))

library(tidyverse)

mtcars |&gt;
  filter(mpg &gt; 25)

mtcars |&gt;
  filter(cyl == 4, gear == 5)





mtcars |&gt;
  select(mpg, wt, cyl)

mtcars |&gt;
  select(-disp, -hp)





mtcars |&gt;
  mutate(kpl = mpg * 0.425,
         heavy = if_else(wt &gt; 3, "Yes", "No"))





mtcars |&gt;
  group_by(cyl) |&gt;
  summarize(
    avg_mpg = mean(mpg),
    sd_mpg = sd(mpg),
    n = n()
  )

Every Shiny app has two parts:

UI (user interface) – what the user sees (inputs, outputs, layout)
Server – the R code that runs behind the scenes (computations, plots)


library(shiny)

ui &lt;- fluidPage(
  titlePanel("My First Shiny App"),
  sidebarLayout(
    sidebarPanel(
      sliderInput("bins", "Number of bins:", min = 5, max = 50, value = 25)
    ),
    mainPanel(
      plotOutput("histogram")
    )
  )
)

server &lt;- function(input, output) {
  output$histogram &lt;- renderPlot({
    hist(faithful$eruptions, breaks = input$bins,
         col = "steelblue", border = "white",
         main = "Old Faithful Eruption Duration",
         xlab = "Duration (minutes)")
  })
}

shinyApp(ui = ui, server = server)

Reactivity is what makes Shiny powerful. When an input changes, only the outputs that depend on it re-execute.

server &lt;- function(input, output) {

  # Reactive expression -- computed once, used by multiple outputs
  filtered_data &lt;- reactive({
    mtcars |&gt; filter(cyl == input$cyl_select)
  })

  output$plot &lt;- renderPlot({
    ggplot(filtered_data(), aes(x = wt, y = mpg)) +
      geom_point(size = 3) +
      theme_minimal()
  })

  output$summary &lt;- renderTable({
    filtered_data() |&gt;
      summarize(avg_mpg = mean(mpg), avg_wt = mean(wt), n = n())
  })
}

# Define the model
log_spec &lt;- logistic_reg() |&gt;
  set_engine("glm") |&gt;
  set_mode("classification")

# Fit on training data
log_fit &lt;- log_spec |&gt;
  fit(am ~ wt + hp + mpg, data = car_train)

# View coefficients
tidy(log_fit)




# Predict on test data
log_preds &lt;- log_fit |&gt;
  predict(car_test) |&gt;
  bind_cols(car_test)

# Confusion matrix
log_preds |&gt;
  conf_mat(truth = am, estimate = .pred_class)

# Accuracy
log_preds |&gt;
  accuracy(truth = am, estimate = .pred_class)

library(rpart)
library(rpart.plot)

# Define the model
tree_spec &lt;- decision_tree() |&gt;
  set_engine("rpart") |&gt;
  set_mode("classification")

# Fit
tree_fit &lt;- tree_spec |&gt;
  fit(am ~ wt + hp + mpg + cyl, data = car_train)

# Visualize the tree
tree_fit |&gt;
  extract_fit_engine() |&gt;
  rpart.plot(roundint = FALSE)




tree_preds &lt;- tree_fit |&gt;
  predict(car_test) |&gt;
  bind_cols(car_test)

tree_preds |&gt;
  conf_mat(truth = am, estimate = .pred_class)

tree_preds |&gt;
  accuracy(truth = am, estimate = .pred_class)
